INSERT INTO public.questions VALUES ('07d1441e-7e69-4485-a834-3e3d58660874', 'bb14ea96-6097-4ee4-adae-5ea04fae28d8', 'radio', 'Questions 1-6', '', '<p id="p-rc_a3450196707ef0f1-23" data-path-to-node="4,0,0"><span class="citation-334 citation-335">Choose</span><strong data-path-to-node="4,0,0" data-index-in-node="0"><span class="citation-334 citation-335"> TRUE </span></strong><span class="citation-334 citation-335 citation-end-335">if the statement agrees with the information,<sup class="superscript" data-turn-source-index="5"><!----></sup></span><span class="citation-334 citation-end-334"><sup class="superscript" data-turn-source-index="6"><!----></sup></span><strong data-path-to-node="4,1,0" data-index-in-node="0"><span class="citation-332 citation-333">FALSE </span></strong><span class="citation-332 citation-333 citation-end-333">if the statement c<sup class="superscript" data-turn-source-index="7"><!----></sup></span><span class="citation-332 citation-end-332">ontradicts the inform<sup class="superscript" data-turn-source-index="8"><!----></sup></span>ation,<strong data-path-to-node="4,2,0" data-index-in-node="0">NOT GIVE </strong> if there is no information on this</p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p> </p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "True"}, {"option_text": "False"}, {"option_text": "Not Given"}], "question": "The lack of interest in the fine arts in Victoria in the 1850s was due to a gold rush taking place."}, {"correct": 2, "options": [{"option_text": "True"}, {"option_text": "False"}, {"option_text": "Not Given"}], "question": "Victoria was the poorest area of Australia before the gold rush."}, {"correct": 0, "options": [{"option_text": "True"}, {"option_text": "False"}, {"option_text": "Not Given"}], "question": "There was disagreement on the purpose of the public art museum in the Melbourne Public Library."}, {"correct": 1, "options": [{"option_text": "True"}, {"option_text": "False"}, {"option_text": "Not Given"}], "question": "The casts in the Museum of Art were arranged according to where they came from."}, {"correct": 1, "options": [{"option_text": "True"}, {"option_text": "False"}, {"option_text": "Not Given"}], "question": "The Intercolonial Exhibition was housed in a pre-existing permanent exhibition centre in Melbourne."}, {"correct": 0, "options": [{"option_text": "True"}, {"option_text": "False"}, {"option_text": "Not Given"}], "question": "Critical comment on Australian art was improved by the Intercolonial Exhibition."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. The lack of interest in the fine arts in Victoria in the 1850s was due to a gold rush taking place. — {TRUE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“In general, the fine arts were not considered to be important at this time. This was <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"106\">partly because there was a gold rush</strong> that was catching people’s attention far more…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận việc thiếu quan tâm đến nghệ thuật thời kỳ này một phần là do cơn sốt vàng đang thu hút sự chú ý của mọi người. Câu hỏi khớp hoàn toàn với thông tin này.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. Victoria was the poorest area of Australia before the gold rush. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> Bài đọc chỉ nói cơn sốt vàng <em data-path-to-node=\"7,0,0\" data-index-in-node=\"49\">“bringing wealth to the people of Victoria”</em> (mang lại sự giàu có cho người dân Victoria).</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài nói cơn sốt vàng mang lại sự giàu có, nhưng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"67\">không hề có thông tin so sánh</strong> Victoria là khu vực “nghèo nhất” (poorest) ở Úc trước thời điểm đó hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. There was disagreement on the purpose of the public art museum in the Melbourne Public Library. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“From the beginning, there were <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"52\">opposing views</strong> about the public art museum’s role. Some people thought… whereas others felt…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Opposing views” (quan điểm đối lập) đồng nghĩa với “disagreement” (sự bất đồng). Một bên muốn bảo tàng tập trung vào lịch sử phát triển nghệ thuật, bên kia muốn trưng bày tranh gốc.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. The casts in the Museum of Art were arranged according to where they came from. — {FALSE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Instead of genuine sculptures, casts… were obtained and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"79\">grouped chronologically</strong>, that is beginning with examples from ancient times and working through the eras…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói các bản đúc (casts) được sắp xếp theo “nơi xuất xứ” (where they came from). Tuy nhiên, bài đọc khẳng định chúng được sắp xếp theo <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"154\">“trình tự thời gian”</strong> (chronologically/working through the eras). Thông tin này mâu thuẫn trực tiếp.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. The Intercolonial Exhibition was housed in a pre-existing permanent exhibition centre in Melbourne. — {FALSE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…an Intercolonial Exhibition was held in a <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"66\">temporary exhibition building erected</strong> in the library’s grounds.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói triển lãm được tổ chức tại một trung tâm triển lãm “vĩnh viễn có sẵn” (pre-existing permanent). Nhưng thực tế bài đọc ghi là một tòa nhà <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"161\">“tạm thời được dựng lên”</strong> (temporary… erected).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. Critical comment on Australian art was improved by the Intercolonial Exhibition. — {TRUE}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“…the opportunity to compare and evaluate the works of local artists <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"91\">enhanced art criticism</strong>.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “enhanced art criticism” (tăng cường/nâng cao phê bình nghệ thuật) tương ứng với “critical comment… was improved” trong câu hỏi. Triển lãm này đã giúp việc phê bình nghệ thuật địa phương trở nên tốt hơn.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('fcb990b7-e50d-4011-acc2-8a5bd9578bc8', 'ead23295-d611-4644-9614-519cd7eca090', 'radio', 'Questions 1-6', '', '<p id="p-rc_885f6bd75a72dcbe-39" data-path-to-node="6,0,0"><span class="citation-1963">Choose</span><strong data-path-to-node="6,0,0" data-index-in-node="0"><span class="citation-1963"> TRUE</span></strong><span class="citation-1963 citation-end-1963"> if the statement agrees with the information,</span><strong data-path-to-node="6,1,0" data-index-in-node="0"><span class="citation-1962">FALSE</span></strong><span class="citation-1962 citation-end-1962"> if the statement cont</span>radicts the information,<strong data-path-to-node="6,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some of the objects in the new museum were previously displayed in other museums."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Hancock Museum’s visitor numbers were dropping."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The old heating system in the Hancock Museum had stopped working."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The new museum is expected to attract people who used to visit the Hancock Museum."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Improvements have been mainly to the outside of the building."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The building work was finished on time."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">1. Some of the objects in the new museum were previously displayed in other museums. — {TRUE}</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“…housing internationally-important collections from <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"66\">Newcastle University’s Museum of Antiquities and the Shefton Museum</strong>, both of which are now closed.”</em></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bảo tàng mới chứa các bộ sưu tập từ hai bảo tàng khác (đã đóng cửa). Điều này khớp với việc các đồ vật này đã được trưng bày ở các bảo tàng khác trước đó.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">2. The Hancock Museum’s visitor numbers were dropping. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc chỉ nói bảo tàng cần đầu tư để cải thiện cơ sở vật chất (<em data-path-to-node=\"8,0,0\" data-index-in-node=\"76\">“in need of major investment to improved its visitor facilities”</em>).</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Không có thông tin nào đề cập đến việc số lượng khách tham quan đang <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"81\">giảm xuống (dropping)</strong>. Bài đọc có thể nói cơ sở vật chất cũ, nhưng lượng khách tăng hay giảm thì không biết.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">3. The old heating system in the Hancock Museum had stopped working. — {FALSE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“…the original heating system <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"43\">could not provide the sort of environment which the collections require</strong>.”</em></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói hệ thống sưởi <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"38\">không cung cấp được môi trường phù hợp</strong> cho các bộ sưu tập (có thể là quá nóng, quá lạnh hoặc không ổn định), chứ không phải là nó đã <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"171\">ngừng hoạt động (stopped working)</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">4. The new museum is expected to attract people who used to visit the Hancock Museum. — {TRUE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“People are really keen to see what’s inside the new museum because they have in their minds <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"104\">what they saw previously in that building</strong>.”</em></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mọi người muốn xem bên trong bảo tàng mới vì họ vẫn nhớ những gì họ đã xem trước đây trong tòa nhà đó (khách cũ). Điều này khẳng định bảo tàng mong đợi thu hút lại những người từng tham quan trước đây.</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">5. Improvements have been mainly to the outside of the building. — {FALSE}</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“The <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"16\">inside</strong> has undergone a similarly <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"49\">dramatic transformation</strong>…”</em> và <em data-path-to-node=\"14,0,0\" data-index-in-node=\"80\">“so you just don’t expect it to be so <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"118\">modern and hi-tech</strong> when you get in there.”</em></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói cải tạo <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"32\">chủ yếu (mainly)</strong> ở bên ngoài. Nhưng bài đọc khẳng định bên trong cũng có sự thay đổi ngoạn mục, hiện đại và công nghệ cao. Cả hai phần đều được cải tạo mạnh mẽ, không chỉ riêng bên ngoài.</li>\n</ul>\n<p><strong data-path-to-node=\"15\" data-index-in-node=\"0\">6. The building work was finished on time. — {TRUE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">“…but <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"19\">everything has happened according to schedules</strong>.”</em></li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “according to schedules” (theo đúng lịch trình/kế hoạch) đồng nghĩa với việc hoàn thành đúng hạn (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"117\">on time</strong>).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('928edd6f-266a-4914-a507-78ecbe574f9a', '707d2149-fede-4b11-98d0-7336813c5f68', 'radio', 'Questions 6–14', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The number of traffic-free cycle paths in the city is increasing"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You are likely to reach your destination faster if you drive in the city than if you cycle"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "There are numerous days in the winter when the weather prevents you cycling"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Using a bike app to hire a bike is very popular"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You will have to pay a higher price to buy a bike that is light"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Only folding bikes can be taken on local trains at any time"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You need to book to take a bike on a train at least a week before you travel"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "If you are repairing a puncture, you will need a piece of equipment called a tyre lever"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Broken glass is the most common cause of tyre punctures"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">6. The number of traffic-free cycle paths in the city is increasing.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {TRUE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As well as providing a <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"35\">growing number</strong> of cycle paths that are traffic free…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “growing number” (số lượng đang tăng lên) đồng nghĩa với “increasing”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">7. You are likely to reach your destination faster if you drive in the city than if you cycle.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: {FALSE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “A journey in the city by bike is <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"45\">generally quicker</strong> than the same journey by car…” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định đi xe đạp nhanh hơn xe hơi, trong khi câu hỏi nói lái xe nhanh hơn. Đây là thông tin trái ngược.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">8. There are numerous days in the winter when the weather prevents you cycling.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: {FALSE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “However, the weather is <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"36\">rarely so bad</strong> in Plymouth that it will stop you cycling.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói thời tiết “hiếm khi” tệ đến mức ngăn bạn đạp xe, trái ngược với ý “có rất nhiều ngày” (numerous days) trong câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">9. Using a bike app to hire a bike is very popular.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: {NOT GIVEN}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “To get started, you can hire a bike – various apps are available…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc dùng app để thuê xe, nhưng <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"64\">không hề đề cập</strong> đến việc nó có “phổ biến” (popular) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">10. You will have to pay a higher price to buy a bike that is light.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: {TRUE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…ones with <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"25\">lighter frames</strong> and good gears make cycling easier, but are <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"84\">more expensive</strong>.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Xe khung nhẹ hơn thì đắt hơn, khớp hoàn toàn với ý “trả giá cao hơn” (higher price) cho xe nhẹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">11. Only folding bikes can be taken on local trains at any time.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: {FALSE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…if you want to take a bike on a local train <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"59\">at peak times</strong>, you will need one that <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"97\">folds up</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Xe gấp chỉ là bắt buộc vào <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"39\">giờ cao điểm</strong> (peak times). Vào các giờ khác, xe loại nào cũng có thể mang lên (dù không gian hạn chế). Câu hỏi nói “vào bất kỳ lúc nào” (at any time) là sai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">12. You need to book to take a bike on a train at least a week before you travel.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: {NOT GIVEN}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a reservation in advance of your journey is essential.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc yêu cầu phải đặt chỗ trước (reservation in advance), nhưng <strong data-path-to-node=\"16,2,0\" data-index-in-node=\"79\">không quy định cụ thể</strong> là phải trước bao lâu (ví dụ: một tuần).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">13. If you are repairing a puncture, you will need a piece of equipment called a tyre lever.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: {TRUE}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…you’ll also need to buy certain equipment: a pump, a spare inner tube, and <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"90\">tyre levers for mending punctures</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Mending punctures” đồng nghĩa với “repairing a puncture”. Bài đọc xác nhận bạn cần “tyre lever” cho việc này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">14. Broken glass is the most common cause of tyre punctures.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án: {NOT GIVEN}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…see if you can find out the cause, <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"50\">such as</strong> a piece of broken glass…” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc lấy mảnh kính vỡ làm <strong data-path-to-node=\"20,2,0\" data-index-in-node=\"41\">ví dụ</strong> (such as), chứ không khẳng định đây là nguyên nhân “phổ biến nhất” (most common).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('f769a947-6b53-4880-986c-2726372a263d', 'e0087ac9-4b90-47d8-bebc-ab34bacc8bef', 'fillup', 'Questions 15–21', '<div class="flex flex-col text-sm pb-25">
<article class="text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]" dir="auto" tabindex="-1" data-turn-id="request-692808c1-5324-8321-9241-cf1905753e43-23" data-testid="conversation-turn-287" data-scroll-anchor="true" data-turn="assistant">
<div class="text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn" tabindex="-1">
<div class="flex max-w-full flex-col grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="3daf154f-7fb5-4b88-88bb-6a0336027f88" data-message-model-slug="gpt-5-2">
<div class="flex w-full flex-col gap-1 empty:hidden first:pt-[1px]">
<div class="markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling">
<p data-start="86" data-end="117">Complete the sentences below.</p>
<p data-start="119" data-end="176">Choose <strong data-start="126" data-end="143">ONE WORD ONLY</strong> from the text for each answer.</p>
<p data-start="178" data-end="233">Write your answers in boxes 15–21 on your answer sheet.</p>
<p>A lot of people find it hard to challenge colleagues about their poor {behaviour|behavior}.</p>
<p>People are often afraid of causing {conflict} with colleagues if they raise tricky issues.</p>
<p>It is important to select the most suitable {environment} for a difficult talk.</p>
<p>It may help to consult a {friend} for feedback on how you are communicating the main points.</p>
<p>It often works best if the speaker sounds as if they want to find {solutions} to the problem under discussion.</p>
<p>A line manager that fails to communicate may have an excessive {workload}.</p>
<p>If colleagues never have anything good to say, they may lack the appropriate {skills} to make requests appropriately.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</article>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p> </p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. behaviour (hoặc behavior)</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">\"...confronting a co-worker over unsatisfactory <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"59\">behaviour</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài, việc đối mặt (confronting) với hành vi không hài lòng (unsatisfactory behaviour) tương ứng với việc thách thức/đối mặt (challenge) với hành vi kém (poor behaviour) ở câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. conflict</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">\"...we fear being responsible for <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"45\">conflict</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nêu rõ lý do chúng ta không lên tiếng là vì sợ (fear/afraid) phải chịu trách nhiệm cho sự xung đột (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"121\">conflict</strong>) nảy sinh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. environment</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">\"The right <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"22\">environment</strong> is key – you don’t want somewhere too formal...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định môi trường (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"43\">environment</strong>) phù hợp là yếu tố then chốt khi thực hiện một cuộc đối thoại khó khăn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. friend</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">\"...rehearse what you plan to say in front of a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"59\">friend</strong> so you know you are coming across as you wish to.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc luyện tập trước một người bạn (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"48\">friend</strong>) giúp bạn nhận được phản hồi về cách mình truyền đạt các ý chính có đúng như mong muốn hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. solutions</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">\"...you come across as looking for <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"46\">solutions</strong> together.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi sử dụng ngôn ngữ mang tính hỗ trợ, người nói sẽ tạo cảm giác đang cùng nhau tìm kiếm các giải pháp (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"116\">solutions</strong>) cho vấn đề.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. workload</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">\"The useless boss who never gives you feedback is simply struggling with her own extremely heavy <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"108\">workload</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một người sếp (quản lý trực tiếp) không giao tiếp tốt có thể là do họ đang phải đối mặt với khối lượng công việc (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"126\">workload</strong>) quá nặng nề (heavy/excessive).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">21. skills</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">\"The team member who only has negative comments... simply doesn’t have the <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"86\">skills</strong> to ask for what he wants directly.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những đồng nghiệp chỉ có nhận xét tiêu cực (never have anything good to say) thực chất là do họ thiếu các kỹ năng (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"127\">skills</strong>) để đưa ra yêu cầu một cách trực tiếp và tích cực.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('4d29135b-5786-49b2-9df4-cf4a0129c4da', 'fb04392b-e668-4899-a217-26650b1351ae', 'radio', 'Questions 36 - 40', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 3, "options": [{"content": "A the extreme conditions that Polar explorers have to face."}, {"content": "B the unusual quality of the beauty of Polar regions."}, {"content": "C the vital importance of preserving the Arctic environment."}, {"content": "D the personal qualities required of an explorer in Arctic conditions."}], "question": "In paragraph E, the writer describes different types of ice in order to illustrate"}, {"correct": 2, "options": [{"content": "A He expresses a very limited range of ideas."}, {"content": "B He is only willing to discuss things he is familiar with."}, {"content": "C He uses words and phrases that he has previously memorised."}, {"content": "D He is only fluent when talking about naval matters."}], "question": "What is said about the way Franklin communicates?"}, {"correct": 3, "options": [{"content": "A They no longer notice his slowness."}, {"content": "B They start to copy his approach to work."}, {"content": "C They begin to recognise his efforts to overcome his problems."}, {"content": "D They eventually appreciate his good qualities."}], "question": "How does the attitude of the other sailors change towards Franklin?"}, {"correct": 1, "options": [{"content": "A text from a wide variety of sources."}, {"content": "B short, disconnected pieces of text."}, {"content": "C descriptions of the Arctic landscape."}, {"content": "D information about other explorers like Franklin."}], "question": "The chapters of The Discovery of Slowness which describe Franklin''s early years contain"}, {"correct": 0, "options": [{"content": "A it reflects many people''s concern about one aspect of modern life."}, {"content": "B it offers achievable solutions to many of the problems of today."}, {"content": "C it tells the story of someone''s triumph over personal problems."}, {"content": "D it shows how life in the past was less pressured than it is now."}], "question": "The Discovery of Slowness has achieved widespread popularity because"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">36 In paragraph E, the writer describes different types of ice in order to illustrate</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: D. the personal qualities required of an explorer in Arctic conditions.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn E,</span><span class=\"\"> câu cuối:</span> <em class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"29\">“Ice demands a corresponding patience from those who venture onto it. The explorers who have thrived… haven’t usually lacked unusual <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"164\">self-possession</strong>, a considerable <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"196\">capacity for boredom</strong>, and a talent for the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"239\">uncomplaining endurance of suffering</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tác giả mô tả sự hình thành chậm chạp của băng để nhấn mạnh rằng môi trường này đòi hỏi những phẩm chất cá nhân tương ứng (</span><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"135\">personal qualities</strong><span class=\"\">) như sự điềm tĩnh,</span><span class=\"\"> khả năng chịu đựng sự buồn chán và gian khổ.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">37 What is said about the way Franklin communicates?</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: C. He uses words and phrases that he has previously memorised.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn F,</span><span class=\"\"> câu 2:</span> <em class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"26\">“He <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"30\">learns by heart</strong> “entire fleets of words and batteries of responses,” and speaks a languid, bric-a-brac language.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong class=\"\" data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Cụm từ “learns by heart” đồng nghĩa với “memorised” (học thuộc lòng).</span><span class=\"\"> Bài đọc cho biết vì Franklin không thể nói trôi chảy,</span><span class=\"\"> ông phải học thuộc lòng các tập hợp từ và câu trả lời sẵn có để giao tiếp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38 How does the attitude of the other sailors change towards Franklin?</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: D. They eventually appreciate his good qualities.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn F,</span><span class=\"\"> dòng 5-8:</span> <em class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"29\">“In the Navy, his method… initially <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"67\">provokes mockery</strong> from his fellow sailors. But Franklin persists… and <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"138\">gradually earns the respect</strong> of those around him.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> * Thái độ ban đầu:</span><span class=\"\"> Chế nhạo (</span><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"41\">mockery</strong><span class=\"\">).</span></p>\n<ul data-path-to-node=\"9,2,1\">\n<li>\n<p data-path-to-node=\"9,2,1,0,0\"><span class=\"\">Thái độ sau đó:</span><span class=\"\"> Dần có được sự tôn trọng (</span><strong class=\"\" data-path-to-node=\"9,2,1,0,0\" data-index-in-node=\"42\">earns the respect</strong><span class=\"\">).</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,1,1,0\"><span class=\"\">Sự tôn trọng chính là việc họ bắt đầu trân trọng (</span><strong class=\"\" data-path-to-node=\"9,2,1,1,0\" data-index-in-node=\"50\">appreciate</strong><span class=\"\">) những phẩm chất của ông.</span><span class=\"\"> (Lưu ý:</span><span class=\"\"> Bài không nói họ “copy” – sao chép cách làm của ông,</span><span class=\"\"> nên không chọn B).</span></p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">39 The chapters of The Discovery of Slowness which describe Franklin’s early years contain</strong></p>\n<ul class=\"animating\" data-path-to-node=\"12\">\n<li class=\"animating\">\n<p class=\"animating\" data-path-to-node=\"12,0,0\"><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: B. short, disconnected pieces of text.</strong></p>\n</li>\n<li class=\"animating\">\n<p class=\"animating\" data-path-to-node=\"12,1,0\"><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn G,</span> câu 2: <em data-path-to-node=\"12,1,0\" data-index-in-node=\"26\">“The chapters describing Franklin’s early years are a <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"80\">medley of separate fragments</strong>, rhetorical questions, associative jumps…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “separate fragments” (những mảnh vụn tách biệt) tương ứng với “disconnected pieces of text” (những đoạn văn bản rời rạc).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">40 The Discovery of Slowness has achieved widespread popularity because</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án: A. it reflects many people’s concern about one aspect of modern life.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn H, câu 4: <em data-path-to-node=\"15,1,0\" data-index-in-node=\"26\">“The various groups that have taken the novel up have one thing in common: a <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"103\">dislike of the high-speed culture of Postmodernity</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cuốn sách nổi tiếng vì nó phản ánh sự không hài lòng của nhiều người đối với văn hóa tốc độ cao của đời sống hiện đại (<strong data-path-to-node=\"15,2,0\" data-index-in-node=\"131\">modern life</strong>), điều mà họ đang lo lắng hoặc phản đối.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('46b7ec13-8858-4865-8575-3b8fcce2e136', '18318151-caed-4803-a0d4-9381160a306a', 'matching', 'Questions 21–26', '<p>What do the students say about each of the following websites?</p>
<p>Choose SIX correct answers, A-H, next to questions 21-26.</p>
', '<p>What do the students say about each of the following websites?</p>
<p>Choose <strong>SIX</strong> correct answers, <strong>A</strong>-<strong>H</strong>, next to questions 21-26.</p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Websites</strong></p>\n<p>National Geographic {C. Contains a useful tool for users}</p>\n<p> </p>\n<p>United Nations {A. Information is not freely accessible}</p>\n<p> </p>\n<p>Energy Information Administration {G some information is missing}</p>\n<p> </p>\n<p>British Petroleum {B. Too detailed for their purposes}</p>\n<p> </p>\n<p>Central Intelligence Agency {E. Up-to-date information}</p>\n<p> </p>\n<p>World Bank {H useful historical information}</p>", "answerOptions": [{"optionText": "A. Information is not freely accessible"}, {"optionText": "B. Too detailed for their purposes"}, {"optionText": "C. Contains a useful tool for users"}, {"optionText": "D. Convenient format"}, {"optionText": "E. Up-to-date information"}, {"optionText": "F difficult to navigate"}, {"optionText": "G some information is missing"}, {"optionText": "H useful historical information"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear two students called Charlie and Delia discussing a joint assignment for their human Geography course. First you have some time to look at questions 21 to 26 on page five. Now listen carefully and answer questions 21 to 26.</p>\n<p><strong>Charlie:</strong> Hi Delia, shall we get down to planning our assignment? We haven’t got long now before the deadline.</p>\n<p><strong>Delia:</strong> I know, and it’s quite open ended, isn’t it? Just research and analyse data about energy consumption in a given region.</p>\n<p><strong>Charlie:</strong> Yes, and all we’ve done so far is check out a few likely websites. Shall we exchange ideas about those first? Hmm, good idea. Let me look at my notes.</p>\n<p><strong>Charlie:</strong> Okay. I had a preliminary look at one or two websites. There was National Geographic. The thing there that struck me was a facility for creating tailor made maps. We might like to use that when it comes to presenting our findings. <strong>(21) (C)</strong>.</p>\n<p><strong>Delia:</strong> Right, that would make some types of data instantly clear. My guess also I checked out the United Nations website. That one had masses of useful stuff.</p>\n<p><strong>Charlie:</strong> Only I couldn’t get at it. <strong>(22) I know, it was for subscribers only (A)</strong>.</p>\n<p><strong>Delia:</strong> Right, and we don’t want to get into that sort of thing. After all, it’s not a major piece of work we’re doing.</p>\n<p><strong>Charlie:</strong> Yes, I agree. I looked at the website of an agency called the Energy Information Administration. There were some population statistics there that we could use, but <strong>(23) there didn’t seem to be any figures for energy use (G)</strong>. So that site would only be suitable to a limited extent for our purposes.</p>\n<p><strong>Delia:</strong> I thought the British Petroleum website might be a good place to get information about energy use.</p>\n<p><strong>Charlie:</strong> Oh, good thinking. There was lots of data actually. Uh, the only thing is <strong>(24) it went into more depth than was necessary for our assignment (B)</strong>, and we’d have to collate a lot of the figures to arrive at an overview. So I didn’t think it was quite what we were looking for.</p>\n<p><strong>Delia:</strong> I also looked on the Central Intelligence Agency website.</p>\n<p><strong>Charlie:</strong> Hmm, I never had thought of that. Something worth noting: <strong>(25) it seemed to be the only place I looked at that had data for this current year (E)</strong>.</p>\n<p><strong>Delia:</strong> Oh, right. I’m not sure about the websites I looked at. I didn’t look carefully enough, I guess. And I also found stuff on the World Bank site, and that had <strong>(26) figures going back quite a long way (H)</strong>. Okay.</p>\n<hr>\n<p><strong>Narrator:</strong> Before you hear the rest of the discussion, you have some time to look at questions 27 to 30 on page six. Now listen and answer questions 27 to thirty.</p>\n<p><strong>Charlie:</strong> Fine. We know roughly what we’re doing, but have you got any more definite thoughts about what our subject matter should be?</p>\n<p><strong>Delia:</strong> I think one thing we’ve got to be careful about is biting off more than we can chew. <strong>(27/28) </strong></p>\n<p><strong>Charlie: Yes (B)</strong>, especially as it doesn’t count towards our final assessment anyway.</p>\n<p><strong>Delia:</strong> So shall we just limit it to data about population size and energy consumption?</p>\n<p><strong>Charlie</strong>: How about if we add in one other factor: carbon emissions? I think it would be interesting to see what the interaction between those three factors is like.</p>\n<p><strong>Delia:</strong> Okay, but in that case, we originally planned to stick to countries in North and South America, but what if we narrowed it down further?</p>\n<p><strong>Charlie: </strong>I’d be happy with that. How about let’s say 20 countries in all—<strong>the top 10 consumers of energy in the region and also the bottom ten (D)</strong>? <strong>(27/28)</strong></p>\n<p><strong>Delia:</strong> Hmm, sounds good. And we can calculate per capita consumption and per capita emissions to allow valid comparisons.</p>\n<p><strong>Charlie: </strong>Actually, it would be interesting to look at a breakdown of the types of energy each of those countries uses. You know, how much coal, how much wind power, how much nuclear power, and so on.</p>\n<p><strong>Delia: </strong>But we did just agree to restrict our data.</p>\n<p><strong>Charlie:</strong> I know. And then what about the way we present our data? Our tutor said that’s one of the things she’ll be looking at in particular, especially our graphics. Don’t you think a bar chart would be more effective than a set of tables with figures?</p>\n<p><strong>Delia:</strong> It might, but I’ve got another idea. I’m keen to display our data on a map instead.  We can easily find a software program to do that </p>\n<p><strong>Charlie:</strong> Brilliant, thanks.</p>\n<p><strong>Delia: </strong>One last thing, Charlie, and then we better go away and get started. Who’s going to do what?</p>\n<p><strong>Charlie</strong>: Your math is better than mine, so <strong> [29B] </strong> <span style=\"background-color: #fecc02;\">I’ll volunteer to </span><span style=\"background-color: #fecc02;\">search out all of the raw data we need</span><strong> </strong>if you’re prepared to do the necessary number crunching.</p>\n<p><strong>Delia:</strong> Okay, but can you get them to me as soon as possible?</p>\n<p><strong>Charlie: </strong>I’ll do it tonight.</p>\n<p><strong>Delia:</strong> Okay. And I tell you what, since the graphics were my idea, I’ll take those on, <strong>[30E]</strong> <span style=\"background-color: #fecc02;\"> but do you mind doing the text? You’ve got a better way with words than I have. </span></p>\n<p><span style=\"background-color: #ffffff;\"><strong>Charlie:</strong> </span><span style=\"background-color: #fecc02;\">That’s okay with me, as long as you’ll agree to look over everything and give it the finishing touches before we hand it in.</span><strong><span style=\"background-color: #fecc02;\"><span style=\"background-color: #ffffff;\"> </span></span></strong><span style=\"background-color: #fecc02;\"><span style=\"background-color: #ffffff;\">I</span><span style=\"background-color: #ffffff;\">t’s a deal.</span></span><strong><span style=\"background-color: #ffffff;\"> </span></strong>Shall we meet at the same time tomorrow or do…</p>\n<p><strong>Narrator:</strong> That is the end of Section 3. You now have half a minute to check your answers. Now turn to Section 4 on page 7.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('221c464d-cc13-4bba-ba00-3aaf0ca13bca', 'e0087ac9-4b90-47d8-bebc-ab34bacc8bef', 'fillup', 'Questions 22–27', '<article class="text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]" dir="auto" tabindex="-1" data-turn-id="5bc5919d-17a9-4317-b86b-2afbb85e8af5" data-testid="conversation-turn-289" data-scroll-anchor="false" data-turn="assistant">
<div class="text-base my-auto mx-auto [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn" tabindex="-1">
